package com.anthropic.core.component

import kotlinx.coroutines.flow.Flow

/**
 * Component — one entity, all protocols.
 *
 * Generated by api-gen from OpenAPI schema.
 * Each component handles REST, SSE, WS, WebDAV, MCP for one entity type.
 *
 * T = entity type (e.g. Pet, Order, Message)
 */
interface Component<T> {

    /** Entity type name (e.g. "pet", "order") */
    val name: String

    // --- Read (no PatchEvent) ---

    suspend fun get(id: String): T
    suspend fun list(params: Map<String, String> = emptyMap()): List<T>

    // --- Mutations (all return PatchEvent) ---

    suspend fun add(entity: T): PatchEvent<T>
    suspend fun replace(id: String, entity: T): PatchEvent<T>
    suspend fun patch(id: String, ops: List<PatchOperation>): PatchEvent<T>
    suspend fun remove(id: String): PatchEvent<T>

    // --- Streaming (SSE/WS — same PatchEvent) ---

    /** Subscribe to all mutations as Flow of PatchEvents */
    fun changes(): Flow<PatchEvent<T>>
}
